#include <stdio.h>
#include <string.h>

void solveCase() {
    int N; char s[50005];
    if (scanf("%d", &N)!=1) return;
    scanf("%s", s);
    int n = N;
    int d1[50005]; // odd
    int l=0, r=-1;
    for (int i=0;i<n;i++){
        int k = (i>r) ? 1 : (d1[l+r-i] < r-i+1 ? d1[l+r-i] : r-i+1);
        while (i-k>=0 && i+k<n && s[i-k]==s[i+k]) k++;
        d1[i]=k;
        if (i+k-1>r){ l=i-k+1; r=i+k-1; }
    }
    int d2[50005]; // even
    l=0; r=-1;
    for (int i=0;i<n;i++){
        int k = (i>r) ? 0 : (d2[l+r-i+1] < r-i+1 ? d2[l+r-i+1] : r-i+1);
        while (i-k-1>=0 && i+k<n && s[i-k-1]==s[i+k]) k++;
        d2[i]=k;
        if (i+k-1>r){ l=i-k; r=i+k-1; }
    }
    int bestLen=0, bestStart=0;
    for (int i=0;i<n;i++){
        int len = 2*d1[i]-1;
        if (len>bestLen){ bestLen=len; bestStart=i-d1[i]+1; }
        len = 2*d2[i];
        if (len>bestLen){ bestLen=len; bestStart=i-d2[i]; }
    }
    printf("%d\n", bestLen);
    for (int i=0;i<bestLen;i++) putchar(s[bestStart+i]);
    putchar('\n');
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) solveCase();
    return 0;
}

