pair<int,int> longestPal(const string &s){
    int n=s.size();
    vector<int> d1(n), d2(n);
    int l=0,r=-1;
    for(int i=0;i<n;i++){
        int k = (i>r)?1:min(d1[l+r-i], r-i+1);
        while(i-k>=0 && i+k<n && s[i-k]==s[i+k]) ++k;
        d1[i]=k;
        if(i+k-1>r){ l=i-k+1; r=i+k-1; }
    }
    l=0; r=-1;
    for(int i=0;i<n;i++){
        int k = (i>r)?0:min(d2[l+r-i+1], r-i+1);
        while(i-k-1>=0 && i+k<n && s[i-k-1]==s[i+k]) ++k;
        d2[i]=k;
        if(i+k-1>r){ l=i-k; r=i+k-1; }
    }
    int bestLen=0,bestStart=0;
    for(int i=0;i<n;i++){
        int len=2*d1[i]-1;
        if(len>bestLen){ bestLen=len; bestStart=i-d1[i]+1; }
        len=2*d2[i];
        if(len>bestLen){ bestLen=len; bestStart=i-d2[i]; }
    }
    return {bestStart,bestLen};
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; string s; cin>>N>>s;
        auto res=longestPal(s);
        cout<<res.second<<"\n"<<s.substr(res.first,res.second)<<"\n";
    }
    return 0;
}

