import java.io.*;
import java.util.*;

public class Main {
    private static int[] d1, d2;
    private static int[] longestPal(String s){
        int n = s.length();
        d1 = new int[n];
        d2 = new int[n];
        int l=0, r=-1;
        for(int i=0;i<n;i++){
            int k = (i>r) ? 1 : Math.min(d1[l+r-i], r-i+1);
            while(i-k>=0 && i+k<n && s.charAt(i-k)==s.charAt(i+k)) k++;
            d1[i]=k;
            if(i+k-1>r){ l=i-k+1; r=i+k-1; }
        }
        l=0; r=-1;
        for(int i=0;i<n;i++){
            int k = (i>r) ? 0 : Math.min(d2[l+r-i+1], r-i+1);
            while(i-k-1>=0 && i+k<n && s.charAt(i-k-1)==s.charAt(i+k)) k++;
            d2[i]=k;
            if(i+k-1>r){ l=i-k; r=i+k-1; }
        }
        int bestLen=0, bestStart=0;
        for(int i=0;i<n;i++){
            int len = 2*d1[i]-1;
            if(len>bestLen){ bestLen=len; bestStart=i-d1[i]+1; }
            len = 2*d2[i];
            if(len>bestLen){ bestLen=len; bestStart=i-d2[i]; }
        }
        return new int[]{bestStart,bestLen};
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for(int tc=0; tc<T; tc++){
            int N = Integer.parseInt(br.readLine().trim());
            String s = br.readLine().trim();
            int[] res = longestPal(s);
            out.append(res[1]).append('\n');
            out.append(s.substring(res[0], res[0]+res[1])).append('\n');
        }
        System.out.print(out.toString());
    }
}

